                ArchiveVersion::OldGen,
                true,
            ),
        ];
        let modules = vec![
            ModuleRecord::new(
                "C:/Games/Fallout 4/Data/Fallout4.esm",
                ModuleKind::Full,
                ModuleHeaderVersion::Version100,
                true,
            ),
            ModuleRecord::new(
                "C:/Games/Fallout 4/Data/Example.esl",
