        assert_eq!(row_value(&snapshot.modules.rows, MODULE_FULL_LABEL), 1);
        assert_eq!(row_value(&snapshot.modules.rows, MODULE_LIGHT_LABEL), 1);
        assert!(snapshot.problems.is_empty());
        assert!(matches!(
