    #[test]
    fn overview_diagnostics_next_gen_allows_missing_steam_loader_and_missing_f4se_path() {
        let mut installation = installation(Fallout4InstallType::NextGen);
        installation.f4se_plugins_path = None;
        let discovery = report(
