        let UpdateBannerState::Available { releases, .. } = snapshot.update_banner else {
            panic!("expected available update banner");
        };
        assert_eq!(releases[0].display_label(), "v0.7.1 (GitHub)");
        assert_eq!(
            releases[0].action.target,
