    use crate::{
        domain::{
            discovery::{
                ArchiveFormat, ArchiveVersion, Fallout4Installation, ModuleHeaderVersion,
                ModuleKind, SemanticVersion,
            },
            mod_manager::{
                DetectedModManager, ModManagerKind, ModOrganizerDirectories,
